mapper.select:
SELECT e.equipment_id AS equipmentId, e.equipment_code AS equipmentCode, e.equipment_name AS equipmentName, e.equipment_status AS equipmentStatus, e.equipment_grade AS equipmentGrade, ep.equipment_process_name AS equipmentProcessName, fl.factory_line_name AS factoryLineName, es.environment_name AS environmentName FROM equipment e INNER JOIN equipment_process ep ON e.equipment_process_id = ep.equipment_process_id INNER JOIN factory_line fl ON ep.factory_line_id = fl.factory_line_id INNER JOIN environment_standard es ON e.environment_standard_id = es.environment_standard_id WHERE 1 = 1
AND ( e.equipment_code LIKE CONCAT('%', #{request.keyword}, '%') OR e.equipment_name LIKE CONCAT('%', #{request.keyword}, '%') )
AND e.equipment_status = #{request.equipmentStatus}
AND e.equipment_grade = #{request.equipmentGrade}
ORDER BY e.equipment_id DESC
